import { useState } from "react";
import "./App.css";

import Cart from "./Cart";
import Products from "./Products";
import Checkout from "./Checkout";
import Payment from "./Payment";
import Contact from "./Contact";

function App() {
  const [page, setPage] = useState("home");
  const [cartItems, setCartItems] = useState([]);

  return (
    <div>
      <Header
        setPage={setPage}
        cartItems={cartItems}
      />

      {page === "home" && (
        <Home setPage={setPage} />
      )}

      {page === "products" && (
        <Products
          cartItems={cartItems}
          setCartItems={setCartItems}
          setPage={setPage}
        />
      )}

      {page === "delivery" && <DeliveryAreas />}

      {page === "contact" && (
        <Contact setPage={setPage} />
      )}

      {page === "cart" && (
        <Cart
          cartItems={cartItems}
          setCartItems={setCartItems}
          setPage={setPage}
        />
      )}

      {page === "checkout" && (
        <Checkout
          cartItems={cartItems}
          setPage={setPage}
        />
      )}

      {page === "payment" && (
        <Payment
          cartItems={cartItems}
          setPage={setPage}
        />
      )}

      <Footer />
    </div>
  );
}

function Header({ setPage, cartItems }) {
  const cartCount = cartItems.reduce(
    (sum, item) => sum + item.quantity,
    0
  );

  return (
    <header className="header">
      <div
        className="logo"
        onClick={() => setPage("home")}
      >
        RentNest
      </div>

      <nav>
        <a onClick={() => setPage("home")}>
          HOME
        </a>

        <a onClick={() => setPage("products")}>
          OUR PRODUCTS
        </a>

        <a onClick={() => setPage("delivery")}>
          DELIVERY AREAS
        </a>

        <a onClick={() => setPage("contact")}>
          CONTACT US
        </a>

        <a onClick={() => setPage("cart")}>
          CART ({cartCount})
        </a>
      </nav>

      <div className="phone">
        📞 0800 111 313
      </div>
    </header>
  );
}

function Home({ setPage }) {
  return (
    <>
      <section className="features">
        <div>↩️ Flexible Rental</div>
        <div>💲 Affordable Solutions</div>
        <div>✅ Fast Approval</div>
        <div>🔧 Replace or Repair</div>
      </section>

      <section className="hero">
        <div>
          <h1>
            New Zealand's Trusted Rental
            Solution
          </h1>

          <button
            onClick={() => setPage("products")}
          >
            OUR PRODUCTS
          </button>

          <button
            onClick={() => setPage("cart")}
            style={{
              marginLeft: "15px",
              background: "#52796f",
            }}
          >
            VIEW CART
          </button>
        </div>

        <div className="hero-text">
          <p>
            Rent furniture, appliances and
            fitness equipment easily.
          </p>

          <p>
            Fast delivery, affordable weekly
            prices and flexible rentals.
          </p>
        </div>
      </section>
    </>
  );
}

function DeliveryAreas() {
  return (
    <>
      <section className="delivery-hero">
        <h1>Delivery Areas</h1>
      </section>

      <section className="delivery-page">
        <div className="callback-form">
          <h2>Request a callback</h2>

          <div className="form-row">
            <input placeholder="First Name" />
            <input placeholder="Last Name" />
          </div>

          <div className="form-row">
            <input placeholder="Email" />
            <input placeholder="Phone" />
          </div>

          <input placeholder="Post Code or Suburb" />

          <textarea placeholder="Message"></textarea>

          <button>SUBMIT NOW</button>
        </div>

        <div className="map-section">
          <div className="map-title-row">
            <h2>
              📍 Find Your Delivery Region
            </h2>

            <input placeholder="Post Code or Suburb" />
          </div>

          <iframe
            title="map"
            src="https://www.google.com/maps?q=New%20Zealand&output=embed"
            width="100%"
            height="560"
            style={{ border: 0 }}
          ></iframe>
        </div>
      </section>
    </>
  );
}

function Footer() {
  return (
    <footer>
      <div>
        <h2>
          Want to know more about our rentals?
        </h2>

        <h2>Join our mailing list!</h2>

        <input placeholder="First Name" />

        <input placeholder="Email Address" />

        <button>SUBSCRIBE</button>
      </div>

      <div>
        <h3>Pages</h3>

        <p>Home</p>

        <p>Our Products</p>

        <p>Delivery Areas</p>

        <p>Contact Us</p>
      </div>

      <div>
        <h3>Get In Touch</h3>

        <p>📞 0800 111 313</p>
      </div>
    </footer>
  );
}

export default App;
